// HackerGrid.jsx
import { useRef, useEffect } from \"react\";
export default function HackerGrid() {
  const canvasRef = useRef(null);
  useEffect(() => {
    const canvas = canvasRef.current;
    const ctx = canvas.getContext(\"2d\");
    let animationFrameId;
    const PARTICLE_COUNT = 100;
    const CONNECTION_DISTANCE = 100;
    const MOUSE_RADIUS = 150;
    const COLOR_PARTICLE = \"#39ff14\";
    const COLOR_LINE = \"rgba(57, 255, 20, 0.15)\";
    let particles = [];
    const mouse = { x: null, y: null };
    const resizeCanvas = () => {
      canvas.width = window.innerWidth;
      canvas.height = window.innerHeight;
      particles = Array(PARTICLE_COUNT).fill().map(() => ({ x: Math.random() * canvas.width, y: Math.random() * canvas.height, vx: (Math.random() - 0.5) * 0.5, vy: (Math.random() - 0.5) * 0.5, size: 1.5 }));
    };
    const animate = () => {
      ctx.clearRect(0, 0, canvas.width, canvas.height);
      particles.forEach((p) => {
        p.x += p.vx; p.y += p.vy;
        if (mouse.x) { const dx = mouse.x - p.x, dy = mouse.y - p.y, d = Math.hypot(dx, dy); if (d < MOUSE_RADIUS) { p.x += dx * 0.01; p.y += dy * 0.01; } }
        if (p.x < 0) p.x = canvas.width; if (p.x > canvas.width) p.x = 0;
        if (p.y < 0) p.y = canvas.height; if (p.y > canvas.height) p.y = 0;
        ctx.fillStyle = COLOR_PARTICLE; ctx.beginPath(); ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2); ctx.fill();
      });
      for (let i = 0; i < particles.length; i++) { for (let j = i + 1; j < particles.length; j++) { const d = Math.hypot(particles[i].x - particles[j].x, particles[i].y - particles[j].y); if (d < CONNECTION_DISTANCE) { ctx.strokeStyle = COLOR_LINE; ctx.lineWidth = 0.5; ctx.beginPath(); ctx.moveTo(particles[i].x, particles[i].y); ctx.lineTo(particles[j].x, particles[j].y); ctx.stroke(); } } }
      animationFrameId = requestAnimationFrame(animate);
    };
    window.addEventListener(\"mousemove\", (e) => { mouse.x = e.clientX; mouse.y = e.clientY; });
    window.addEventListener(\"mouseout\", () => { mouse.x = null; mouse.y = null; });
    resizeCanvas(); animate();
    return () => { cancelAnimationFrame(animationFrameId); window.removeEventListener(\"mousemove\", () => {}); };
  }, []);
  return <canvas ref={canvasRef} className=\"absolute inset-0 -z-10 bg-black\" />;
}

// VoidPulse.jsx
import { useRef, useEffect } from \"react\";
export default function VoidPulse() {
  const canvasRef = useRef(null);
  useEffect(() => {
    const canvas = canvasRef.current;
    const ctx = canvas.getContext(\"2d\");
    let animationFrameId;
    const RIPPLE_COLOR = \"rgba(59, 130, 246, 0.4)\";
    const RIPPLE_SPEED = 4;
    const DECAY_RATE = 0.98;
    const ripples = [];
    const resizeCanvas = () => { canvas.width = window.innerWidth; canvas.height = window.innerHeight; };
    const animate = () => {
      ctx.clearRect(0, 0, canvas.width, canvas.height);
      for (let i = ripples.length - 1; i >= 0; i--) {
        const r = ripples[i];
        r.radius += RIPPLE_SPEED; r.opacity *= DECAY_RATE;
        ctx.strokeStyle = RIPPLE_COLOR; ctx.lineWidth = 2 * r.opacity; ctx.beginPath(); ctx.ellipse(r.x, r.y, r.radius, r.radius * 0.5, 0, 0, Math.PI * 2); ctx.stroke();
        if (r.opacity < 0.01) ripples.splice(i, 1);
      }
      animationFrameId = requestAnimationFrame(animate);
    };
    window.addEventListener(\"click\", (e) => { ripples.push({ x: e.clientX, y: e.clientY, radius: 1, opacity: 1 }); });
    resizeCanvas(); animate();
    return () => { cancelAnimationFrame(animationFrameId); };
  }, []);
  return <canvas ref={canvasRef} className=\"absolute inset-0 -z-10 bg-black\" />;
}

// GlitchNoise.jsx
import { useRef, useEffect } from \"react\";
export default function GlitchNoise() {
  const canvasRef = useRef(null);
  useEffect(() => {
    const canvas = canvasRef.current;
    const ctx = canvas.getContext(\"2d\");
    let animationFrameId;
    const BLOCK_SIZE = 5;
    const IDLE_SPEED = 0.1;
    const INTERACTION_SPEED = 0.9;
    const INTENSITY_RADIUS = 200;
    const mouse = { x: null, y: null };
    const resizeCanvas = () => { canvas.width = window.innerWidth; canvas.height = window.innerHeight; };
    const animate = () => {
      ctx.fillStyle = \"rgba(0, 0, 0, 0.1)\"; ctx.fillRect(0, 0, canvas.width, canvas.height);
      for (let x = 0; x < canvas.width; x += BLOCK_SIZE) {
        for (let y = 0; y < canvas.height; y += BLOCK_SIZE) {
          let speed = IDLE_SPEED;
          if (mouse.x) { const d = Math.hypot(mouse.x - x, mouse.y - y); if (d < INTENSITY_RADIUS) speed = INTERACTION_SPEED * (1 - d / INTENSITY_RADIUS); }
          if (Math.random() < speed) { ctx.fillStyle = Math.random() < 0.95 ? \"#111\" : \"#fff\"; ctx.fillRect(x, y, BLOCK_SIZE, BLOCK_SIZE); }
        }
      }
      animationFrameId = requestAnimationFrame(animate);
    };
    window.addEventListener(\"mousemove\", (e) => { mouse.x = e.clientX; mouse.y = e.clientY; });
    window.addEventListener(\"mouseout\", () => { mouse.x = null; mouse.y = null; });
    resizeCanvas(); animate();
    return () => { cancelAnimationFrame(animationFrameId); };
  }, []);
  return <canvas ref={canvasRef} className=\"absolute inset-0 -z-10 bg-black\" />;
}

// CipherText.jsx
import React, { useState, useEffect } from \"react\";
export const CipherText = ({ text = \"SYSTEM GRANTED\", delay = 0 }) => {
  const [displayText, setDisplayText] = useState(\"\");
  const letters = \"ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789!@#$%^&*\";
  useEffect(() => {
    let iteration = 0; let interval = null;
    const startAnimation = () => {
      clearInterval(interval);
      interval = setInterval(() => {
        setDisplayText(text.split(\"\").map((letter, index) => { if (index < iteration) { return text[index]; } return letters[Math.floor(Math.random() * letters.length)]; }).join(\"\"));
        if (iteration >= text.length) { clearInterval(interval); }
        iteration += 1 / 3;
      }, 30);
    };
    const timeout = setTimeout(startAnimation, delay);
    return () => { clearInterval(interval); clearTimeout(timeout); };
  }, [text, delay]);
  return <span className=\"font-mono font-black tracking-widest text-[#39ff14] drop-shadow-[0_0_8px_rgba(57,255,20,0.8)]\">{displayText}</span>;
};

